class Command(BaseCommand):
    help = "Erstellt Beispiel-FAQs für die Joel Digitals Website"

    def add_arguments(self, parser):
        parser.add_argument(
            '--force',
            action='store_true',
            help='Überschreibt vorhandene FAQs (löscht alle zuerst)'
        )

    def handle(self, *args, **options):
        if options['force']:
            count = FAQ.objects.count()
            FAQ.objects.all().delete()
            self.stdout.write(f"Gelöscht: {count} alte FAQs")

        created = 0
        skipped = 0
        for data in FAQS:
            _, was_created = FAQ.objects.get_or_create(
                question_de=data["question_de"],
                defaults={
                    "question_en": data["question_en"],
                    "short_answer_de": data["short_answer_de"],
                    "short_answer_en": data["short_answer_en"],
                    "answer_de": data["answer_de"],
                    "answer_en": data["answer_en"],
                    "detail_content_de": data.get("detail_content_de", ""),
                    "detail_content_en": data.get("detail_content_en", ""),
                    "order": data["order"],
                    "is_published": True,
                }
            )
            if was_created:
                created += 1
            else:
                skipped += 1

        self.stdout.write(self.style.SUCCESS(
            f"Fertig! {created} FAQs erstellt, {skipped} übersprungen (bereits vorhanden)."
        ))
